class TestOptionsSpyOverboughtPutBias(unittest.TestCase):
    def test_sets_short_bias_above_80(self):
        bias, reason = heuristic_options_spy_overbought_put_bias(82.5, None)
        self.assertEqual(bias, "short")
        self.assertIn("82.5", reason)

    def test_preserves_existing_bias_below_80(self):
        bias, _ = heuristic_options_spy_overbought_put_bias(74.0, "long")
        self.assertEqual(bias, "long")

    def test_preserves_none_bias_below_80(self):
        bias, reason = heuristic_options_spy_overbought_put_bias(70.0, None)
        self.assertIsNone(bias)
        self.assertEqual(reason, "")

    def test_exact_threshold_triggers(self):
        bias, _ = heuristic_options_spy_overbought_put_bias(80.1, None)
        self.assertEqual(bias, "short")

    def test_at_threshold_no_trigger(self):
        bias, _ = heuristic_options_spy_overbought_put_bias(80.0, None)
        self.assertIsNone(bias)
